// Pass 5: block merging.  Walk forward; after a successful merge, keep
// trying to merge the same BB with its (new) successor.
{
  std::vector<BasicBlock*> bbs;
  for (auto& bb : F)
    bbs.push_back(&bb);
  for (BasicBlock* bb : bbs) {
    // The BB might have been erased by an earlier merge.
    if (bb->getParent() != &F)
      continue;
    while (mergeWithSingleSuccessor(*bb)) {
      changed = true;
    }
  }
}

action.new_str:
// Pass 5: block merging.  Repeat until no more merges happen this
// iteration.  We re-scan every time to avoid stale pointers.
bool mergedSomething = true;
while (mergedSomething) {
  mergedSomething = false;
  for (auto it = F.begin(); it != F.end();) {
    auto& bb = *it++;
    if (mergeWithSingleSuccessor(bb)) {
      mergedSomething = true;
      changed = true;
      break; // start over to invalidate `it`-safety concerns
    }
  }
}

